detailed_optimizations.code_changes:
将循环顺序从i-j-k改为i-k-j，并添加分块：
for (ii = 0; ii < _PB_NI; ii += TILE_I)
  for (kk = 0; kk < _PB_NK; kk += TILE_K)
    for (jj = 0; jj < _PB_NJ; jj += TILE_J)
      for (i = ii; i < min(ii+TILE_I, _PB_NI); i++)
        for (k = kk; k < min(kk+TILE_K, _PB_NK); k++)
          for (j = jj; j < min(jj+TILE_J, _PB_NJ); j++)
            E[i][j] += A[i][k] * B[k][j];

类似E的计算，将循环顺序从i-j-k改为i-k-j，并添加分块：
for (ii = 0; ii < _PB_NJ; ii += TILE_J)
  for (kk = 0; kk < _PB_NM; kk += TILE_M)
    for (jj = 0; jj < _PB_NL; jj += TILE_L)
      for (i = ii; i < min(ii+TILE_J, _PB_NJ); i++)
        for (k = kk; k < min(kk+TILE_M, _PB_NM); k++)
          for (j = jj; j < min(jj+TILE_L, _PB_NL); j++)
            F[i][j] += C[i][k] * D[k][j];

类似前两个乘法，将循环顺序从i-j-k改为i-k-j，并添加分块：
for (ii = 0; ii < _PB_NI; ii += TILE_I)
  for (kk = 0; kk < _PB_NJ; kk += TILE_J)
    for (jj = 0; jj < _PB_NL; jj += TILE_L)
      for (i = ii; i < min(ii+TILE_I, _PB_NI); i++)
        for (k = kk; k < min(kk+TILE_J, _PB_NJ); k++)
          for (j = jj; j < min(jj+TILE_L, _PB_NL); j++)
            G[i][j] += E[i][k] * F[k][j];

将三个矩阵乘法替换为BLAS库调用：
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans, ni, nj, nk, 1.0, A, nk, B, nj, 0.0, E, nj);
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans, nj, nl, nm, 1.0, C, nm, D, nl, 0.0, F, nl);
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans, ni, nl, nj, 1.0, E, nj, F, nl, 0.0, G, nl);

在计算前对B、D、F矩阵进行转置，使内存访问连续：
